    {"offset": {"line": 120, "column": 0}, "map": {"version":3,"sources":["file:///C:/wamp64/www/pedidos/src/components/ui/dialog.tsx"],"sourcesContent":["import * as React from \"react\"\nimport * as DialogPrimitive from \"@radix-ui/react-dialog\"\nimport { X } from \"lucide-react\"\n\nimport { cn } from \"@/lib/utils\"\n\nconst Dialog = DialogPrimitive.Root\n\nconst DialogTrigger = DialogPrimitive.Trigger\n\nconst DialogPortal = DialogPrimitive.Portal\n\nconst DialogClose = DialogPrimitive.Close\n\nconst DialogOverlay = React.forwardRef<\n  React.ElementRef<typeof DialogPrimitive.Overlay>,\n  React.ComponentPropsWithoutRef<typeof DialogPrimitive.Overlay>\n>(({ className, ...props }, ref) => (\n  <DialogPrimitive.Overlay\n    ref={ref}\n    className={cn(\n      \"fixed inset-0 z-50 bg-black/80  data-[state=open]:animate-in data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=open]:fade-in-0\",\n      className\n    )}\n    {...props}\n  />\n))\nDialogOverlay.displayName = DialogPrimitive.Overlay.displayName\n\nconst DialogContent = React.forwardRef<\n  React.ElementRef<typeof DialogPrimitive.Content>,\n  React.ComponentPropsWithoutRef<typeof DialogPrimitive.Content>\n>(({ className, children, ...props }, ref) => (\n  <DialogPortal>\n    <DialogOverlay />\n    <DialogPrimitive.Content\n      ref={ref}\n      className={cn(\n        \"fixed left-[50%] top-[50%] z-50 grid w-full max-w-lg translate-x-[-50%] translate-y-[-50%] gap-4 border bg-background p-6 shadow-lg duration-200 data-[state=open]:animate-in data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=open]:fade-in-0 data-[state=closed]:zoom-out-95 data-[state=open]:zoom-in-95 data-[state=closed]:slide-out-to-left-1/2 data-[state=closed]:slide-out-to-top-[48%] data-[state=open]:slide-in-from-left-1/2 data-[state=open]:slide-in-from-top-[48%] sm:rounded-lg\",\n        className\n      )}\n      {...props}\n    >\n      {children}\n      <DialogPrimitive.Close className=\"absolute right-4 top-4 rounded-sm opacity-70 ring-offset-background transition-opacity hover:opacity-100 focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2 disabled:pointer-events-none data-[state=open]:bg-accent data-[state=open]:text-muted-foreground\">\n        <X className=\"h-4 w-4\" />\n        <span className=\"sr-only\">Close</span>\n      </DialogPrimitive.Close>\n    </DialogPrimitive.Content>\n  </DialogPortal>\n))\nDialogContent.displayName = DialogPrimitive.Content.displayName\n\nconst DialogHeader = ({\n  className,\n  ...props\n}: React.HTMLAttributes<HTMLDivElement>) => (\n  <div\n    className={cn(\n      \"flex flex-col space-y-1.5 text-center sm:text-left\",\n      className\n    )}\n    {...props}\n  />\n)\nDialogHeader.displayName = \"DialogHeader\"\n\nconst DialogFooter = ({\n  className,\n  ...props\n}: React.HTMLAttributes<HTMLDivElement>) => (\n  <div\n    className={cn(\n      \"flex flex-col-reverse sm:flex-row sm:justify-end sm:space-x-2\",\n      className\n    )}\n    {...props}\n  />\n)\nDialogFooter.displayName = \"DialogFooter\"\n\nconst DialogTitle = React.forwardRef<\n  React.ElementRef<typeof DialogPrimitive.Title>,\n  React.ComponentPropsWithoutRef<typeof DialogPrimitive.Title>\n>(({ className, ...props }, ref) => (\n  <DialogPrimitive.Title\n    ref={ref}\n    className={cn(\n      \"text-lg font-semibold leading-none tracking-tight\",\n      className\n    )}\n    {...props}\n  />\n))\nDialogTitle.displayName = DialogPrimitive.Title.displayName\n\nconst DialogDescription = React.forwardRef<\n  React.ElementRef<typeof DialogPrimitive.Description>,\n  React.ComponentPropsWithoutRef<typeof DialogPrimitive.Description>\n>(({ className, ...props }, ref) => (\n  <DialogPrimitive.Description\n    ref={ref}\n    className={cn(\"text-sm text-muted-foreground\", className)}\n    {...props}\n  />\n))\nDialogDescription.displayName = DialogPrimitive.Description.displayName\n\nexport {\n  Dialog,\n  DialogPortal,\n  DialogOverlay,\n  DialogTrigger,\n  DialogClose,\n  DialogContent,\n  DialogHeader,\n  DialogFooter,\n  DialogTitle,\n  DialogDescription,\n}\n"],"names":[],"mappings":";;;;;;;;;;;;;;;;;;;;;;;AAAA;AACA;AACA;AAEA;;;;;;AAEA,MAAM,SAAS,0KAAoB;AAEnC,MAAM,gBAAgB,6KAAuB;AAE7C,MAAM,eAAe,4KAAsB;AAE3C,MAAM,cAAc,2KAAqB;AAEzC,MAAM,8BAAgB,mNAAgB,CAGpC,CAAC,EAAE,SAAS,EAAE,GAAG,OAAO,EAAE,oBAC1B,8OAAC,6KAAuB;QACtB,KAAK;QACL,WAAW,IAAA,yHAAE,EACX,2JACA;QAED,GAAG,KAAK;;;;;;AAGb,cAAc,WAAW,GAAG,6KAAuB,CAAC,WAAW;AAE/D,MAAM,8BAAgB,mNAAgB,CAGpC,CAAC,EAAE,SAAS,EAAE,QAAQ,EAAE,GAAG,OAAO,EAAE,oBACpC,8OAAC;;0BACC,8OAAC;;;;;0BACD,8OAAC,6KAAuB;gBACtB,KAAK;gBACL,WAAW,IAAA,yHAAE,EACX,+fACA;gBAED,GAAG,KAAK;;oBAER;kCACD,8OAAC,2KAAqB;wBAAC,WAAU;;0CAC/B,8OAAC,iMAAC;gCAAC,WAAU;;;;;;0CACb,8OAAC;gCAAK,WAAU;0CAAU;;;;;;;;;;;;;;;;;;;;;;;;AAKlC,cAAc,WAAW,GAAG,6KAAuB,CAAC,WAAW;AAE/D,MAAM,eAAe,CAAC,EACpB,SAAS,EACT,GAAG,OACkC,iBACrC,8OAAC;QACC,WAAW,IAAA,yHAAE,EACX,sDACA;QAED,GAAG,KAAK;;;;;;AAGb,aAAa,WAAW,GAAG;AAE3B,MAAM,eAAe,CAAC,EACpB,SAAS,EACT,GAAG,OACkC,iBACrC,8OAAC;QACC,WAAW,IAAA,yHAAE,EACX,iEACA;QAED,GAAG,KAAK;;;;;;AAGb,aAAa,WAAW,GAAG;AAE3B,MAAM,4BAAc,mNAAgB,CAGlC,CAAC,EAAE,SAAS,EAAE,GAAG,OAAO,EAAE,oBAC1B,8OAAC,2KAAqB;QACpB,KAAK;QACL,WAAW,IAAA,yHAAE,EACX,qDACA;QAED,GAAG,KAAK;;;;;;AAGb,YAAY,WAAW,GAAG,2KAAqB,CAAC,WAAW;AAE3D,MAAM,kCAAoB,mNAAgB,CAGxC,CAAC,EAAE,SAAS,EAAE,GAAG,OAAO,EAAE,oBAC1B,8OAAC,iLAA2B;QAC1B,KAAK;QACL,WAAW,IAAA,yHAAE,EAAC,iCAAiC;QAC9C,GAAG,KAAK;;;;;;AAGb,kBAAkB,WAAW,GAAG,iLAA2B,CAAC,WAAW"}},
    {"offset": {"line": 259, "column": 0}, "map": {"version":3,"sources":["file:///C:/wamp64/www/pedidos/src/components/ui/input.tsx"],"sourcesContent":["import * as React from \"react\"\n\nimport { cn } from \"@/lib/utils\"\n\nconst Input = React.forwardRef<HTMLInputElement, React.ComponentProps<\"input\">>(\n  ({ className, type, ...props }, ref) => {\n    return (\n      <input\n        type={type}\n        className={cn(\n          \"flex h-9 w-full rounded-md border border-input bg-transparent px-3 py-1 text-base shadow-sm transition-colors file:border-0 file:bg-transparent file:text-sm file:font-medium file:text-foreground placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring disabled:cursor-not-allowed disabled:opacity-50 md:text-sm\",\n          className\n        )}\n        ref={ref}\n        {...props}\n      />\n    )\n  }\n)\nInput.displayName = \"Input\"\n\nexport { Input }\n"],"names":[],"mappings":";;;;;AAAA;AAEA;;;;AAEA,MAAM,sBAAQ,mNAAgB,CAC5B,CAAC,EAAE,SAAS,EAAE,IAAI,EAAE,GAAG,OAAO,EAAE;IAC9B,qBACE,8OAAC;QACC,MAAM;QACN,WAAW,IAAA,yHAAE,EACX,2WACA;QAEF,KAAK;QACJ,GAAG,KAAK;;;;;;AAGf;AAEF,MAAM,WAAW,GAAG"}},
    {"offset": {"line": 287, "column": 0}, "map": {"version":3,"sources":["file:///C:/wamp64/www/pedidos/src/components/ui/textarea.tsx"],"sourcesContent":["import * as React from \"react\"\n\nimport { cn } from \"@/lib/utils\"\n\nconst Textarea = React.forwardRef<\n  HTMLTextAreaElement,\n  React.ComponentProps<\"textarea\">\n>(({ className, ...props }, ref) => {\n  return (\n    <textarea\n      className={cn(\n        \"flex min-h-[60px] w-full rounded-md border border-input bg-transparent px-3 py-2 text-base shadow-sm placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring disabled:cursor-not-allowed disabled:opacity-50 md:text-sm\",\n        className\n      )}\n      ref={ref}\n      {...props}\n    />\n  )\n})\nTextarea.displayName = \"Textarea\"\n\nexport { Textarea }\n"],"names":[],"mappings":";;;;;AAAA;AAEA;;;;AAEA,MAAM,yBAAW,mNAAgB,CAG/B,CAAC,EAAE,SAAS,EAAE,GAAG,OAAO,EAAE;IAC1B,qBACE,8OAAC;QACC,WAAW,IAAA,yHAAE,EACX,6QACA;QAEF,KAAK;QACJ,GAAG,KAAK;;;;;;AAGf;AACA,SAAS,WAAW,GAAG"}},
    {"offset": {"line": 314, "column": 0}, "map": {"version":3,"sources":["file:///C:/wamp64/www/pedidos/src/app/%28dashboard%29/visits/page.tsx"],"sourcesContent":["\"use client\";\n\nimport { useEffect, useState } from 'react';\nimport { useAuth } from '@/contexts/AuthContext';\nimport { useRouter } from 'next/navigation';\nimport { Visit, User } from '@/types';\nimport { Button } from '@/components/ui/button';\nimport {\n  Table,\n  TableBody,\n  TableCell,\n  TableHead,\n  TableHeader,\n  TableRow,\n} from '@/components/ui/table';\nimport {\n  Dialog,\n  DialogContent,\n  DialogHeader,\n  DialogTitle,\n} from '@/components/ui/dialog';\nimport { Input } from '@/components/ui/input';\nimport { Textarea } from '@/components/ui/textarea';\nimport { formatDate } from '@/lib/utils';\nimport { Plus, Trash2 } from 'lucide-react';\nimport { useToast } from '@/hooks/use-toast';\n\nexport default function VisitsPage() {\n  const { user } = useAuth();\n  const router = useRouter();\n  const { toast } = useToast();\n\n  const [visits, setVisits] = useState<Visit[]>([]);\n  const [dentists, setDentists] = useState<User[]>([]);\n  const [loading, setLoading] = useState(true);\n  const [dialogOpen, setDialogOpen] = useState(false);\n  const [formDate, setFormDate] = useState<string>('');\n  const [formTitle, setFormTitle] = useState<string>('');\n  const [formNotes, setFormNotes] = useState<string>('');\n  const [selectedDentists, setSelectedDentists] = useState<string[]>([]);\n\n  useEffect(() => {\n    if (!user) return;\n    if (user.role !== 'admin') {\n      router.push('/dashboard');\n      return;\n    }\n    fetchDentists();\n    fetchVisits();\n  }, [user, router]);\n\n  const fetchDentists = async () => {\n    try {\n      const res = await fetch('/api/users');\n      if (!res.ok) return;\n      const data: any[] = await res.json();\n      const onlyDentists = data.filter((u) => u.role === 'dentist');\n      setDentists(\n        onlyDentists.map((u) => ({\n          id: u.id,\n          username: u.username,\n          name: u.name,\n          role: 'dentista',\n        }))\n      );\n    } catch (error) {\n      console.error('Error fetching dentists', error);\n    }\n  };\n\n  const fetchVisits = async () => {\n    try {\n      const res = await fetch('/api/visits');\n      if (!res.ok) return;\n      const data: Visit[] = await res.json();\n      setVisits(data);\n    } catch (error) {\n      console.error('Error fetching visits', error);\n      toast({\n        variant: 'destructive',\n        title: 'Error',\n        description: 'No se pudieron cargar las visitas',\n      });\n    } finally {\n      setLoading(false);\n    }\n  };\n\n  const resetForm = () => {\n    setFormDate('');\n    setFormTitle('');\n    setFormNotes('');\n    setSelectedDentists([]);\n  };\n\n  const handleCreate = async (e: React.FormEvent) => {\n    e.preventDefault();\n    if (!formDate || !formTitle || selectedDentists.length === 0) {\n      toast({\n        variant: 'destructive',\n        title: 'Datos incompletos',\n        description:\n          'Debes indicar fecha, título y al menos un dentista para la visita.',\n      });\n      return;\n    }\n    try {\n      const res = await fetch('/api/visits', {\n        method: 'POST',\n        headers: {\n          'Content-Type': 'application/json',\n        },\n        body: JSON.stringify({\n          date: new Date(formDate).toISOString(),\n          title: formTitle,\n          notes: formNotes || undefined,\n          dentistIds: selectedDentists,\n        }),\n      });\n      if (!res.ok) {\n        const err = await res.json().catch(() => null);\n        toast({\n          variant: 'destructive',\n          title: 'Error',\n          description: err?.error || 'No se pudo crear la visita',\n        });\n        return;\n      }\n      toast({\n        title: 'Visita creada',\n        description: 'La visita ha sido programada correctamente.',\n      });\n      setDialogOpen(false);\n      resetForm();\n      fetchVisits();\n    } catch (error) {\n      console.error('Error creating visit', error);\n      toast({\n        variant: 'destructive',\n        title: 'Error',\n        description: 'Ocurrió un error inesperado',\n      });\n    }\n  };\n\n  const handleDelete = async (id: number) => {\n    if (!confirm('¿Eliminar esta visita?')) return;\n    try {\n      const res = await fetch(`/api/visits/${id}`, {\n        method: 'DELETE',\n      });\n      if (!res.ok) {\n        toast({\n          variant: 'destructive',\n          title: 'Error',\n          description: 'No se pudo eliminar la visita',\n        });\n        return;\n      }\n      toast({\n        title: 'Visita eliminada',\n        description: 'La visita ha sido eliminada correctamente.',\n      });\n      setVisits((prev) => prev.filter((v) => v.id !== id));\n    } catch (error) {\n      console.error('Error deleting visit', error);\n    }\n  };\n\n  const toggleDentist = (id: string) => {\n    setSelectedDentists((prev) =>\n      prev.includes(id) ? prev.filter((d) => d !== id) : [...prev, id]\n    );\n  };\n\n  if (loading) return <div className=\"p-6\">Cargando visitas...</div>;\n\n  return (\n    <div className=\"container mx-auto p-6 space-y-6\">\n      <div className=\"flex justify-between items-center\">\n        <div>\n          <h1 className=\"text-3xl font-bold tracking-tight\">\n            Programación de Visitas\n          </h1>\n          <p className=\"text-muted-foreground\">\n            Agenda las visitas presenciales a los dentistas.\n          </p>\n        </div>\n        <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>\n          <Button\n            className=\"gap-2\"\n            onClick={() => {\n              resetForm();\n              setDialogOpen(true);\n            }}\n          >\n            <Plus className=\"h-4 w-4\" />\n            Nueva visita\n          </Button>\n          <DialogContent>\n            <DialogHeader>\n              <DialogTitle>Programar nueva visita</DialogTitle>\n            </DialogHeader>\n            <form onSubmit={handleCreate} className=\"space-y-4 py-4\">\n              <div className=\"space-y-2\">\n                <label className=\"text-sm font-medium\" htmlFor=\"date\">\n                  Fecha de visita\n                </label>\n                <Input\n                  id=\"date\"\n                  type=\"date\"\n                  value={formDate}\n                  onChange={(e) => setFormDate(e.target.value)}\n                  required\n                />\n              </div>\n              <div className=\"space-y-2\">\n                <label className=\"text-sm font-medium\" htmlFor=\"title\">\n                  Título / Motivo\n                </label>\n                <Input\n                  id=\"title\"\n                  value={formTitle}\n                  onChange={(e) => setFormTitle(e.target.value)}\n                  required\n                />\n              </div>\n              <div className=\"space-y-2\">\n                <label className=\"text-sm font-medium\" htmlFor=\"notes\">\n                  Notas\n                </label>\n                <Textarea\n                  id=\"notes\"\n                  value={formNotes}\n                  onChange={(e) => setFormNotes(e.target.value)}\n                  placeholder=\"Información adicional sobre la visita...\"\n                />\n              </div>\n              <div className=\"space-y-2\">\n                <div className=\"flex items-center justify-between\">\n                  <p className=\"text-sm font-medium\">Dentistas a visitar</p>\n                  {dentists.length > 0 && (\n                    <div className=\"flex gap-2\">\n                      <Button\n                        type=\"button\"\n                        variant=\"outline\"\n                        size=\"sm\"\n                        onClick={() =>\n                          setSelectedDentists(dentists.map((d) => d.id))\n                        }\n                      >\n                        Seleccionar todos\n                      </Button>\n                      <Button\n                        type=\"button\"\n                        variant=\"ghost\"\n                        size=\"sm\"\n                        onClick={() => setSelectedDentists([])}\n                      >\n                        Limpiar\n                      </Button>\n                    </div>\n                  )}\n                </div>\n                <div className=\"max-h-60 overflow-auto border rounded-md p-2 space-y-1\">\n                  {dentists.length === 0 ? (\n                    <p className=\"text-xs text-gray-500\">\n                      No hay dentistas registrados.\n                    </p>\n                  ) : (\n                    dentists.map((d) => (\n                      <label\n                        key={d.id}\n                        className=\"flex items-center gap-2 text-sm\"\n                      >\n                        <input\n                          type=\"checkbox\"\n                          className=\"h-4 w-4 rounded border-gray-300\"\n                          checked={selectedDentists.includes(d.id)}\n                          onChange={() => toggleDentist(d.id)}\n                        />\n                        <span>{d.name}</span>\n                      </label>\n                    ))\n                  )}\n                </div>\n              </div>\n              <div className=\"flex justify-end gap-2 pt-2\">\n                <Button\n                  type=\"button\"\n                  variant=\"outline\"\n                  onClick={() => setDialogOpen(false)}\n                >\n                  Cancelar\n                </Button>\n                <Button type=\"submit\">Guardar visita</Button>\n              </div>\n            </form>\n          </DialogContent>\n        </Dialog>\n      </div>\n\n      <div className=\"border rounded-lg\">\n        <Table>\n          <TableHeader>\n            <TableRow>\n              <TableHead>Fecha</TableHead>\n              <TableHead>Título</TableHead>\n              <TableHead>Dentistas</TableHead>\n              <TableHead>Notas</TableHead>\n              <TableHead className=\"w-[80px] text-right\">Acciones</TableHead>\n            </TableRow>\n          </TableHeader>\n          <TableBody>\n            {visits.length === 0 ? (\n              <TableRow>\n                <TableCell colSpan={5} className=\"text-center py-6\">\n                  No hay visitas programadas.\n                </TableCell>\n              </TableRow>\n            ) : (\n              visits.map((visit) => (\n                <TableRow key={visit.id}>\n                  <TableCell>{formatDate(visit.date)}</TableCell>\n                  <TableCell>{visit.title}</TableCell>\n                  <TableCell>\n                    {visit.dentists.map((d) => d.name).join(', ') || '—'}\n                  </TableCell>\n                  <TableCell className=\"max-w-xs truncate\">\n                    {visit.notes || '—'}\n                  </TableCell>\n                  <TableCell className=\"text-right\">\n                    <Button\n                      size=\"icon\"\n                      variant=\"ghost\"\n                      onClick={() => handleDelete(visit.id)}\n                    >\n                      <Trash2 className=\"h-4 w-4 text-red-600\" />\n                    </Button>\n                  </TableCell>\n                </TableRow>\n              ))\n            )}\n          </TableBody>\n        </Table>\n      </div>\n    </div>\n  );\n}\n"],"names":[],"mappings":";;;;;AAEA;AACA;AACA;AAEA;AACA;AAQA;AAMA;AACA;AACA;AACA;AAAA;AACA;AAzBA;;;;;;;;;;;;;AA2Be,SAAS;IACtB,MAAM,EAAE,IAAI,EAAE,GAAG,IAAA,0IAAO;IACxB,MAAM,SAAS,IAAA,+IAAS;IACxB,MAAM,EAAE,KAAK,EAAE,GAAG,IAAA,wIAAQ;IAE1B,MAAM,CAAC,QAAQ,UAAU,GAAG,IAAA,iNAAQ,EAAU,EAAE;IAChD,MAAM,CAAC,UAAU,YAAY,GAA